SELECT 'SATISFACTION' AS "metricName", ROUND(AVG(satisfaction_score), 2) AS "avgValue", ROUND(STDDEV(satisfaction_score), 2) AS "stddevValue", MIN(satisfaction_score) AS "minValue", MAX(satisfaction_score) AS "maxValue" FROM SURVEY WHERE created_at >= #{startDate} AND created_at < #{endDate}
UNION ALL
SELECT 'INFO_RELIABILITY' AS "metricName", ROUND(AVG(info_reliability_score), 2) AS "avgValue", ROUND(STDDEV(info_reliability_score), 2) AS "stddevValue", MIN(info_reliability_score) AS "minValue", MAX(info_reliability_score) AS "maxValue" FROM SURVEY WHERE created_at >= #{startDate} AND created_at < #{endDate}
UNION ALL
SELECT 'NPS' AS "metricName", ROUND(AVG(nps_score), 2) AS "avgValue", ROUND(STDDEV(nps_score), 2) AS "stddevValue", MIN(nps_score) AS "minValue", MAX(nps_score) AS "maxValue" FROM SURVEY WHERE created_at >= #{startDate} AND created_at < #{endDate}

SELECT answerText FROM ( SELECT inconvenience AS answerText , created_at FROM SURVEY WHERE inconvenience IS NOT NULL AND created_at >= #{startDate} AND created_at < #{endDate}
UNION ALL
SELECT improvements AS answerText , created_at FROM SURVEY WHERE improvements IS NOT NULL AND created_at >= #{startDate} AND created_at < #{endDate} ) WHERE answerText IS NOT NULL

        SELECT COUNT(*)
          FROM SURVEY
         WHERE CREATED_AT >= #{startDate, jdbcType=TIMESTAMP}
	       AND CREATED_AT < #{endDate, jdbcType=TIMESTAMP}
